noncompliant:
#include <sys/capability.h>

// Granting excessive capabilities
cap_t caps = cap_init();
cap_value_t cap_list[5];
cap_list[0] = CAP_SYS_ADMIN; // Noncompliant: very broad capability
cap_list[1] = CAP_SYS_RAWIO;
cap_list[2] = CAP_NET_ADMIN;
cap_list[3] = CAP_DAC_OVERRIDE;
cap_list[4] = CAP_SETUID;
cap_set_flag(caps, CAP_PERMITTED, 5, cap_list, CAP_SET);
cap_set_proc(caps); // Noncompliant: granting too many capabilities

compliant:
#include <sys/capability.h>

// Grant only necessary specific capabilities
cap_t caps = cap_init();
cap_value_t cap_list[1];
cap_list[0] = CAP_NET_BIND_SERVICE; // Compliant: specific capability for binding to privileged ports
cap_set_flag(caps, CAP_PERMITTED, 1, cap_list, CAP_SET);
cap_set_flag(caps, CAP_EFFECTIVE, 1, cap_list, CAP_SET);
cap_set_proc(caps); // Compliant: minimal required capability
cap_free(caps);
